def read_books():
    books = []
    try:
        with open(os.path.join(DATA_DIR, 'booksdata.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split(',')
                if len(parts) < 8:
                    continue
                # bookID(str), name(int), authorName(int), isbn_code(int), category(int), cost(str), stock_count(str), desc(list)
                book = {
                    'bookID': parts[0],
                    'name': int(parts[1]),
                    'authorName': int(parts[2]),
                    'isbn_code': int(parts[3]),
                    'category': int(parts[4]),
                    'cost': parts[5],
                    'stock_count': parts[6],
                    'desc': parts[7:]  # List of strings
                }
                books.append(book)
    except FileNotFoundError:
        pass
    return books


def write_books(books):
    try:
        with open(os.path.join(DATA_DIR, 'booksdata.txt'), 'w', encoding='utf-8') as f:
