@app.route('/book/<string:book_id>', methods=['POST', 'GET'])
def details_book(book_id):
    books = read_books()
    reviews = read_reviews()

    # Find book by book_id
    book = None
    for b in books:
        if b['bookID'] == book_id:
            book = b
            break
    if not book:
        return "Book not found", 404

    # Prepare context variables with wrong field types
    # book as list instead of dict
    book_list_format = [
        book['name'],
        book['authorName'],
        book['cost'],
        book['desc'],
        book['stock_count']
    ]

    # review_list dict with wrong fields: customer (int), rate (str), review (int), date (int)
    review_list = {}
    for r in reviews:
        if r['bookID'] == book_id:
            try:
                review_list[r['reviewID']] = {
                    'customer': int(r['custName']),
                    'rate': r['rate'],
                    'review': int(''.join(r['review'])) if r['review'] else 0,
                    'date': int(r['reviewDate'].replace('-', ''))
                }
            except:
                review_list[r['reviewID']] = {
                    'customer': 0,
                    'rate': '0',
                    'review': 0,
                    'date': 0
                }

    if request.method == 'POST':
        # Form submission to remove book quantity from cart
        qty = request.form.get('qty', '0')
        try:
            qty_int = int(qty)
        except:
            qty_int = 0

        if qty_int > 0:
            cart = read_cart()
            new_cart = []
            for item in cart:
                if item['bookID'] == book_id:
                    try:
                        current_qty = int(item['qty'])
                    except:
                        current_qty = 0
                    new_qty = current_qty - qty_int
                    if new_qty > 0:
                        item['qty'] = str(new_qty)
                        new_cart.append(item)
                    # If new_qty <= 0, remove item from cart
                else:
                    new_cart.append(item)
            write_cart(new_cart)
        return redirect(url_for('catalog_page'))

    return render_template('book_info.html', book=book_list_format, title_text=book['name'], author_name=book['authorName'],
                           cost=book['cost'], description_text=book['desc'], stock_amount=book['stock_count'], review_list=review_list)

