# Save applications function for data update

def save_applications(applications):
    try:
        with open('data/applications.txt', 'w', encoding='utf-8') as f:
            for app in applications:
                line = '|'.join([
                    str(app['application_id']),
                    str(app['job_id']),
                    app['applicant_name'],
                    app['applicant_email'],
                    app['status'],
                    app['applied_date'],
                    str(app['resume_id'])
                ])
                f.write(line + '\n')
    except Exception:
        pass


