# Utility functions to load data files and parse the pipe-delimited formats

def load_jobs():
    jobs = []
    try:
        with open('data/jobs.txt', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 9:
                    continue
                job_id = int(parts[0])
                title = parts[1]
                company_id = parts[2]  # Will link later with companies
                location = parts[3]
                # salary_min and max should be int if possible, but some may be strings
                try:
                    salary_min = int(parts[4])
                except ValueError:
                    salary_min = parts[4]  # as string if non-integer
                try:
                    salary_max = int(parts[5])
                except ValueError:
                    salary_max = parts[5]  # as string
                category = parts[6]
                description = parts[7]
                posted_date = parts[8]
                jobs.append({
                    'job_id': job_id,
                    'title': title,
                    'company_id': company_id,
                    'location': location,
                    'salary_min': salary_min,
                    'salary_max': salary_max,
                    'category': category,
                    'description': description,
                    'posted_date': posted_date
                })
    except FileNotFoundError:
        pass
    return jobs


