@app.route('/make_reservation', methods=['GET', 'POST'])
def make_reservtions():
    if request.method == 'GET':
        # On GET redirect or show error message per spec (spec says redirect or error)
        return redirect(url_for('dashbord'))

    # POST: receive form fields: guest_name, party_size, reservation_date
    guest_name = request.form.get('guest_nam')
    party_size = request.form.get('party_siz')
    reservation_date = request.form.get('reservation_dat')

    if not guest_name or not party_size or not reservation_date:
        # Missing required fields
        return "Missing reservation details", 400

    # Load current user info
    users = load_users()
    user = users.get(CURRENT_USERNAME)
    if not user:
        return "User not found", 404

    # Generate a new reservation_id (simple max+1 approach)
    reservations = load_reservations()
    max_id = 0
    for r in reservations:
        try:
            rid = int(r['reservation_id'])
            if rid > max_id:
                max_id = rid
        except:
            continue
    new_id = str(max_id + 1)

    # Use default time? Spec doesn't specify time input, so reservation time is not provided, we can assign a default time e.g. 19-00
    reservation_time = '19-00'

    # Compose new reservation
    new_reservation = {
        'reservation_id': new_id,
        'username': CURRENT_USERNAME,
        'guest_name': guest_name,
        'phone': user['phone'],
        'email': user['email'],
        'party_size': party_size,
        'date': reservation_date,
        'time': reservation_time,
        'special_requests': '',
        'status': 'Upcoming'
    }

    # Append new reservation to file
    try:
        with open(os.path.join(DATA_DIR, 'reservations.tx'), 'a') as f:
            line = ','.join([
                new_reservation['reservation_id'],
                new_reservation['username'],
                new_reservation['guest_name'],
                new_reservation['phone'],
                new_reservation['email'],
                new_reservation['party_size'],
                new_reservation['date'],
                new_reservation['time'],
                new_reservation['special_requests'],
                new_reservation['status']
            ])
            f.write(line + '\n')
    except Exception as e:
        return f"Failed to write reservation: {str(e)}", 500

    # Redirect to dashboard after successful reservation
    return redirect(url_for('dashbord'))

