# Helper function to parse pipe delimited lines, thoughtful to clear leading/trailing whitespace
# As the data specs show csv separated by commas but instructions specify pipe-delimited parsing, we will use pipe delimiter here.
def parse_line(line):
    return [field.strip() for field in line.strip().split('|')]

# Load restaurants data from file
# Fields: restaurant_id,name,cuisine,address,phone,rating,delivery_time,min_order
# All are strings except min_order float
# cuisine field might be a comma separated list but spec says list - treat cuisine as single string for now (spec example shows a single string cuisine)
# Return dictionary {restaurant_id: dict of fields}
def load_restaurants():
    path = os.path.join(data_folder, 'restaurants.txt')
    restaurants = {}
    try:
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = parse_line(line)
                if len(parts) < 8:
                    continue
                restaurant_id = parts[0]
                restaurants[restaurant_id] = {
                    'restaurant_id': restaurant_id,
                    'name': parts[1],
                    'cuisine': parts[2],
                    'address': parts[3],
                    'phone': parts[4],
                    'rating': parts[5],
                    'delivery_time': parts[6],
                    'min_order': float(parts[7]) if parts[7] else 0.0
                }
    except FileNotFoundError:
        pass
    except Exception:
        pass
    return restaurants

