                parts = parse_line(line)
                if len(parts) < 7:
                    continue
                item = {
                    'item_id': parts[0],
                    'restaurant_id': parts[1],
                    'item_name': parts[2],
                    'category': parts[3],
                    'description': parts[4],
                    'price': parts[5],
                    'availability': parts[6]
                }
                menu_items.append(item)
    except FileNotFoundError:
        pass
    except Exception:
        pass
    return menu_items

