# Route: /cart POST render cart.html
# Context vars: cart_items dict, total_amount str
@app.route('/cart', methods=['POST'])
def shopping_cart():
    cart_items_raw = load_cart()
    menus = load_menus()
    # Build cart items dict keyed by item_id with quantity sum
    cart = {}
    total_amount = 0.0
    for ci in cart_items_raw:
        menu_item = next((m for m in menus if m['item_id'] == ci['item_id']), None)
        if not menu_item:
            continue
        qty = ci['quantity']
        if ci['item_id'] not in cart:
            cart[ci['item_id']] = {
                'item': menu_item,
                'quantity': qty
            }
        else:
            cart[ci['item_id']]['quantity'] += qty
    # Calculate total
    for entry in cart.values():
        try:
            total_amount += float(entry['item']['price']) * entry['quantity']
        except Exception:
            pass
    total_amount_str = f"{total_amount:.2f}"
    return render_template('cart.html', cart_items=cart, total_amount=total_amount_str)

