# Routes

@app.route('/')
def root():
    return redirect(url_for('dashboard_page'))


@app.route('/dashboard')
def dashboard_page():
    current_weather_data = load_current_weather()
    saved_locations = load_saved_locations()
    # Determine default location
    default_location = None
    for saved in saved_locations:
        if saved['is_default'] == 1:
            # find current weather for this location
            for cw in current_weather_data:
                if cw['location_id'] == saved['location_id']:
                    default_location = cw
                    break
            break
    if default_location is None and len(current_weather_data) > 0:
        default_location = current_weather_data[0]
    # Compose context
    current_weather = {
        'location_id': default_location['location_id'] if default_location else None,
        'location_name': default_location['location_name'] if default_location else '',
        'temperature': default_location['temperature'] if default_location else '',
        'condition': default_location['condition'] if default_location else '',
        'humidity': default_location['humidity'] if default_location else '',
        'wind_speed': default_location['wind_speed'] if default_location else '',
        'last_updated': default_location['last_updated'] if default_location else ''
    }
    return render_template('dashboard.html', current_weather=current_weather)


@app.route('/locations/search', methods=['GET', 'POST'])
def location_search_page():
    locations = load_locations()
    saved_locations_data = load_saved_locations()
    saved_locations = [{'location_id': sl['location_id'], 'location_name': sl['location_name']} for sl in saved_locations_data]
    search_results = []
    search_query = ''

    if request.method == 'POST':
        search_query = request.form.get('search_query', '').strip()
        if search_query:
            search_lower = search_query.lower()
            for loc in locations:
                if search_lower in loc['location_name'].lower():
                    search_results.append({'location_id': loc['location_id'], 'location_name': loc['location_name']})

    return render_template('location_search.html', search_results=search_results, saved_locations=saved_locations, search_query=search_query)


@app.route('/alerts')
def weather_alerts_page():
    alerts = load_alerts()
    severity_levels = ['All', 'Critical', 'High', 'Medium', 'Low']
    locations = load_locations()
    # Convert severity filter by GET param
    filter_severity = request.args.get('severity', 'All')
    filter_location_id = request.args.get('location_id', None)

    filtered_alerts = []
    for alert in alerts:
        if filter_severity != 'All' and alert['severity'] != filter_severity:
            continue
        if filter_location_id is not None and filter_location_id != '' and str(alert['location_id']) != filter_location_id:
            continue
        filtered_alerts.append(alert)

    # Convert location_id in locations to int for template
    locs = [{'location_id': loc['location_id'], 'location_name': loc['location_name']} for loc in locations]

    return render_template('alerts.html', alerts=filtered_alerts,
                           severity_levels=severity_levels, locations=locs)


@app.route('/alerts/acknowledge/<int:alert_id>', methods=['POST'])
def acknowledge_alert(alert_id):
    # Because the specification demands no database or state persistence,
    # we will simulate acknowledge by loading alerts, modifying in-memory and rewriting file.
    alerts = load_alerts()
    changed = False
    for alert in alerts:
        if alert['alert_id'] == alert_id:
            if not alert['is_acknowledged']:
                alert['is_acknowledged'] = True
                changed = True
    if changed:
        # Write back alerts.txt with is_acknowledged changed
        filepath = os.path.join(DATA_DIR, 'alerts.txt')
        try:
            with open(filepath, 'w') as f:
                for alert in alerts:
                    # Write is_acknowledged as 1 or 0
                    ia = '1' if alert['is_acknowledged'] else '0'
                    line = f"{alert['alert_id']}|{alert['location_id']}|{alert['alert_type']}|{alert['severity']}|{alert['description']}|{alert['start_time']}|{alert['end_time']}|{ia}\n"
                    f.write(line)
        except OSError:
            pass
    return redirect(url_for('weather_alerts_page'))


@app.route('/air_quality')
def air_quality_page():
    locations = load_locations()
    aqi_data_list = load_air_quality()
    severity_levels = ['All', 'Critical', 'High', 'Medium', 'Low']

    selected_location_id = request.args.get('location_id', None)
    # If selected_location_id None, select first location id if available
    if not selected_location_id:
        if locations:
            selected_location_id = str(locations[0]['location_id'])
        else:
            selected_location_id = None

    try:
        selected_location_id_int = int(selected_location_id) if selected_location_id else None
    except ValueError:
        selected_location_id_int = None

    aqi_data = None
    if selected_location_id_int is not None:
        for aqi in aqi_data_list:
            if aqi['location_id'] == selected_location_id_int:
                aqi_data = aqi
                break

    # Define aqi description and health recommendation based on AQI index
    aqi_desc = ''
    health_rec = ''
    if aqi_data:
        idx = aqi_data['aqi_index']
        if idx <= 50:
            aqi_desc = 'Good'
            health_rec = 'Air quality is satisfactory, and air pollution poses little or no risk.'
        elif idx <= 100:
            aqi_desc = 'Moderate'
            health_rec = 'Air quality is acceptable; some pollutants may be a concern for a very small number of people.'
        elif idx <= 150:
            aqi_desc = 'Unhealthy for Sensitive Groups'
            health_rec = 'Members of sensitive groups may experience health effects.'
        elif idx <= 200:
            aqi_desc = 'Unhealthy'
            health_rec = 'Everyone may begin to experience health effects; members of sensitive groups may experience more serious health effects.'
        elif idx <= 300:
            aqi_desc = 'Very Unhealthy'
            health_rec = 'Health alert: everyone may experience more serious health effects.'
        else:
            aqi_desc = 'Hazardous'
            health_rec = 'Health warnings of emergency conditions. The entire population is more likely to be affected.'

    context = {
        'locations': [{'location_id': loc['location_id'], 'location_name': loc['location_name']} for loc in locations],
        'selected_location_id': selected_location_id_int,
